import java.util.Arrays;

public static long solve(long[] nums, long k) {
    if (nums.length == 1) {
        return 0;
    }
    Arrays.sort(nums);
    int n = nums.length;
    long minRemovals = Long.MAX_VALUE;

    for (int i = 0; i < n; i++) {
        long min = nums[i];
        long maxAllowed = min * k;
        int left = i, right = n - 1;
        int best = i;

        while (left <= right) {
            int mid = left + (right - left) / 2;
            if (nums[mid] <= maxAllowed) {
                best = mid;
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }

        long removals = i + (n - 1 - best);
        if (removals < minRemovals) {
            minRemovals = removals;
        }
    }

    return minRemovals;
}
