public static long solve(long[] nums, long k) {
    if (nums.length == 1) {
        return 0;
    }
    Arrays.sort(nums);
    int n = nums.length;
    int left = 0;
    int maxLen = 0;
    for (int right = 0; right < n; right++) {
        while (nums[right] > nums[left] * k) {
            left++;
        }
        maxLen = Math.max(maxLen, right - left + 1);
    }
    return n - maxLen;
}
